PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE reactions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    source_id INTEGER,
    reactants TEXT NOT NULL,
    conditions TEXT NOT NULL DEFAULT '',
    product TEXT NOT NULL,
    source TEXT NOT NULL DEFAULT '',
    named_reaction TEXT NOT NULL DEFAULT '',
    category TEXT NOT NULL DEFAULT '',
    difficulty TEXT NOT NULL DEFAULT '',
    transform TEXT NOT NULL DEFAULT '',
    notes TEXT NOT NULL DEFAULT '',
    raw_conditions TEXT NOT NULL DEFAULT '',
    source_row TEXT NOT NULL DEFAULT '',
    error TEXT NOT NULL DEFAULT ''
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_named_reaction ON reactions(named_reaction);
CREATE INDEX idx_category ON reactions(category);
COMMIT;
